	@Test
	void traceShouldSupportOptionalWithCurrentWrappers() {
		SailRepository repository = new SailRepository(new MemoryStore());
		repository.init();

		try {
			addMinimalTraceData(repository);

			try (SailRepositoryConnection connection = repository.getConnection()) {
				TupleQuery query = connection.prepareTupleQuery(
						"SELECT DISTINCT ?a ?name WHERE { ?a <urn:trace:knows> ?person . "
								+ "OPTIONAL { ?person <urn:trace:name> ?name } FILTER(?a != ?person) } LIMIT 5");
				String optimizedPlan = query.explain(Explanation.Level.Optimized).toString();

				QueryTrace trace = query.trace();

				assertThat(optimizedPlan)
						.contains("Slice")
						.contains("Distinct")
						.contains("Filter")
						.contains("LeftJoin");
				assertThat(trace.isSuccess())
						.withFailMessage("trace error %s:%s%nplan:%n%s",
								trace.getError() == null ? "<none>" : trace.getError().getCode(),
								trace.getError() == null ? "<none>" : trace.getError().getMessage(),
								optimizedPlan)
						.isTrue();
				assertThat(trace.isDistinct()).isTrue();
				assertThat(trace.getFilters()).containsExactly("FILTER(?a != ?person)");
				assertThat(trace.getPatterns())
						.extracting(QueryTrace.Pattern::getText, QueryTrace.Pattern::getOptionalDepth)
						.containsExactly(
								org.assertj.core.groups.Tuple.tuple("?a <urn:trace:knows> ?person", 0),
								org.assertj.core.groups.Tuple.tuple("?person <urn:trace:name> ?name", 1));
				assertThat(trace.getFrames()).isNotEmpty();
			}
		} finally {
			repository.shutDown();
		}
	}

	@Test
	void traceShouldFailWhenFrameLimitIsExceeded() {
		SailRepository repository = new SailRepository(new MemoryStore());
		repository.init();
		int resultsNeededToExceedFrameLimit = (QueryTraceRecorder.FRAME_LIMIT + 1) / 2;

		try {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				for (int i = 0; i < resultsNeededToExceedFrameLimit; i++) {
					connection.add(VF.createIRI(EX, "subject-" + i), KNOWS, VF.createIRI(EX, "object-" + i));
				}
				connection.commit();
			}

			try (SailRepositoryConnection connection = repository.getConnection()) {
				TupleQuery query = connection.prepareTupleQuery("SELECT * WHERE { ?s <urn:trace:knows> ?o }");

				QueryTrace trace = query.trace();

				assertThat(trace.isSuccess()).isFalse();
				assertThat(trace.getError()).isNotNull();
				assertThat(trace.getError().getCode()).isEqualTo("traceLimitExceeded");
				assertThat(trace.getFrames()).isEmpty();
			}
		} finally {
			repository.shutDown();
		}
	}

	private static void addMinimalTraceData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.add(ALICE, KIND, PERSON);
			connection.add(ALICE, KNOWS, BOB);
			connection.add(BOB, NAME, bobLiteral());
			connection.commit();
		}
	}

	private static Literal bobLiteral() {
		return VF.createLiteral("Bob");
	}

	private static void assertFrame(QueryTrace.Frame frame, int index, String event, int patternIndex,
			Map<String, String> inputBindings, Map<String, String> outputBindings, Map<String, String> resultBindings) {
		assertThat(frame.getIndex()).isEqualTo(index);
		assertThat(frame.getEvent()).isEqualTo(event);
		assertThat(frame.getPatternIndex()).isEqualTo(patternIndex);
		assertThat(frame.getInputBindings()).isEqualTo(inputBindings);
		assertThat(frame.getOutputBindings()).isEqualTo(outputBindings);
		assertThat(frame.getResultBindings()).isEqualTo(resultBindings);
	}
